noteContentFormat:
{% if title %}
# {{title|split:" - "|first}}
{% endif %}

{% set images = selector:#slide img?src %}
{% for i in images %}  
	{% if loop.first %}## Images{% endif %}
	{% if i contains "http" %}{{i|image|list}}{% endif %}
{% endfor %}

{% set full_description = selectorHtml:section#about|remove_html:("iframe")|markdown %}
{% if full_description %}
## Description
{{full_description}}
{% endif %}

{% set specifications = selectorHtml:#spec table|markdown %}
{% if specifications %}
## Specifications
{{specifications}}
{% endif %}
